module top_module(
  input a,
  input b,
  input c,
  input d,
  output out
);wire ab, cd, not_cd;

  // AND gate for a and b
  assign out = ab & not_cd;

  // OR gate for c and d
  assign not_cd = ~cd;

  // NOT gate for cd
  assign cd = c | d;

  // AND gate for ab and not_cd
  assign ab = a & b;

endmodule
